SELECT model_id, AVG(auc) AS average_auc
FROM model_evaluation
GROUP BY model_id;

SELECT MAX(total_accuracy) AS highest_cumulative_accuracy
FROM (
    SELECT model_id, SUM(accuracy) AS total_accuracy
    FROM model_evaluation
    GROUP BY model_id
) AS model_totals;

SELECT AVG(accuracy) AS average_accuracy
FROM model_evaluation
WHERE experiment_id = 1;

SELECT AVG(auc) AS average_auc
FROM model_evaluation
WHERE experiment_id = 1;
